import{c as a,Q as t,j as i,m as r}from"./chunks/framework.BPKcPtvA.js";const c=JSON.parse('{"title":"智能任务框架","description":"","frontmatter":{},"headers":[],"relativePath":"using-system/task-management/templates.md","filePath":"using-system/task-management/templates.md"}'),e={name:"using-system/task-management/templates.md"};function n(o,l,s,h,d,g){return t(),i("div",null,[...l[0]||(l[0]=[r('<h1 id="智能任务框架" tabindex="-1">智能任务框架 <a class="header-anchor" href="#智能任务框架" aria-label="Permalink to &quot;智能任务框架&quot;">​</a></h1><p>基于预设的业务逻辑与交互框架，快速创建标准化的股权投后管理任务。系统正逐步升级为更智能的AI Skill，实现从机械填报到智能服务的跨越。</p><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>智能任务框架专为股权投后管理业务设计，帮助您高效完成各类投后管理工作：</p><ul><li><strong>企业评分评级</strong>：定期对投资企业进行综合评分和等级评定</li><li><strong>财务数据报送</strong>：按集团统计口径收集和上报企业财务数据</li><li><strong>风险评估</strong>：对投资企业进行定期风险评估</li><li><strong>重大事项报告</strong>：处理和上报企业重大事项</li></ul><h2 id="使用智能任务框架" tabindex="-1">使用智能任务框架 <a class="header-anchor" href="#使用智能任务框架" aria-label="Permalink to &quot;使用智能任务框架&quot;">​</a></h2><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h3><ol><li><p><strong>打开任务创建页面</strong></p></li><li><p><strong>选择任务类型</strong></p><ul><li>点击表单底部中的「选择任务类型」按钮</li><li>打开任务类型选择弹窗 <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260525162616931.png" alt="选择任务类型"></li></ul></li><li><p><strong>筛选任务类型</strong></p><ul><li>通过分类标签筛选：评分评级档案卡、财务报告框架等</li><li>使用搜索框输入关键词搜索 <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260525162707053.png" alt="筛选任务类型"></li></ul></li><li><p><strong>预览与应用</strong></p><ul><li>点击任务类型卡片查看详细内容</li><li>确认后点击「应用」按钮</li><li>任务表单自动填充预设内容 <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260525162745362.png" alt="应用任务类型"></li></ul></li></ol><h3 id="应用效果示例" tabindex="-1">应用效果示例 <a class="header-anchor" href="#应用效果示例" aria-label="Permalink to &quot;应用效果示例&quot;">​</a></h3><p>应用任务类型后，表单自动填充：</p><ul><li>任务标题（含类型名称和周期信息）</li><li>任务描述（含执行说明和要求）</li><li>任务分类和优先级（按预设配置）</li><li>关联表单和参考文档</li></ul><h2 id="任务框架管理" tabindex="-1">任务框架管理 <a class="header-anchor" href="#任务框架管理" aria-label="Permalink to &quot;任务框架管理&quot;">​</a></h2><h3 id="框架库界面" tabindex="-1">框架库界面 <a class="header-anchor" href="#框架库界面" aria-label="Permalink to &quot;框架库界面&quot;">​</a></h3><p><img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260525162707053.png" alt="框架库"></p><p>框架库提供以下功能：</p><ul><li><strong>分类浏览</strong>：按业务类型分类展示任务框架</li><li><strong>搜索过滤</strong>：支持关键词搜索和条件筛选</li><li><strong>收藏管理</strong>：收藏常用框架便于快速访问</li><li><strong>使用统计</strong>：查看框架使用频次和反馈</li></ul><h3 id="创建自定义任务框架" tabindex="-1">创建自定义任务框架 <a class="header-anchor" href="#创建自定义任务框架" aria-label="Permalink to &quot;创建自定义任务框架&quot;">​</a></h3><ol><li>点击框架库右上角「新建框架」</li><li>填写框架基本信息：名称、分类、适用范围</li><li>设计框架内容：标题模板、描述模板、表单字段</li><li>配置框架参数：默认优先级、截止时间规则、通知设置</li><li>上传相关附件：参考文档、表单模板等</li><li>保存并发布框架</li></ol><h3 id="框架版本管理" tabindex="-1">框架版本管理 <a class="header-anchor" href="#框架版本管理" aria-label="Permalink to &quot;框架版本管理&quot;">​</a></h3><ul><li><strong>版本记录</strong>：自动保存框架修改历史</li><li><strong>版本对比</strong>：查看不同版本间的差异</li><li><strong>版本回滚</strong>：恢复到历史版本</li><li><strong>版本发布</strong>：控制框架生效时间</li></ul><h3 id="内容规范要求" tabindex="-1">内容规范要求 <a class="header-anchor" href="#内容规范要求" aria-label="Permalink to &quot;内容规范要求&quot;">​</a></h3><ul><li>严格按照预设格式填写内容</li><li>财务数据需符合集团统计口径</li><li>评分评级需依据统一标准执行</li><li>附件需按要求命名和格式上传</li></ul><h3 id="框架更新管理" tabindex="-1">框架更新管理 <a class="header-anchor" href="#框架更新管理" aria-label="Permalink to &quot;框架更新管理&quot;">​</a></h3><ul><li>定期关注框架更新通知</li><li>及时使用最新版本框架</li><li>反馈框架使用问题和改进建议</li></ul><h2 id="向ai-skill演进" tabindex="-1">向AI Skill演进 <a class="header-anchor" href="#向ai-skill演进" aria-label="Permalink to &quot;向AI Skill演进&quot;">​</a></h2><h3 id="演进背景" tabindex="-1">演进背景 <a class="header-anchor" href="#演进背景" aria-label="Permalink to &quot;演进背景&quot;">​</a></h3><p>当前的任务框架系统正在逐步转型为更智能的AI Skill，这是系统智能化升级的重要战略方向。</p><h3 id="核心理念转变" tabindex="-1">核心理念转变 <a class="header-anchor" href="#核心理念转变" aria-label="Permalink to &quot;核心理念转变&quot;">​</a></h3><p>从传统框架到AI Skill，代表着从「机械填报」到「智能服务」的根本性转变：</p><table tabindex="0"><thead><tr><th>维度</th><th>传统框架</th><th>AI Skill（演进方向）</th></tr></thead><tbody><tr><td><strong>核心定位</strong></td><td>任务框架库</td><td>智能任务助手</td></tr><tr><td><strong>交互方式</strong></td><td>表单填写</td><td>自然语言交互</td></tr><tr><td><strong>处理模式</strong></td><td>被动接收</td><td>主动理解</td></tr><tr><td><strong>响应方式</strong></td><td>机械校验</td><td>智能生成</td></tr><tr><td><strong>学习能力</strong></td><td>无</td><td>持续进化</td></tr></tbody></table><h3 id="演进路径" tabindex="-1">演进路径 <a class="header-anchor" href="#演进路径" aria-label="Permalink to &quot;演进路径&quot;">​</a></h3><p>系统正沿着以下路径逐步演进：</p><h4 id="第一阶段-标准化框架-当前" tabindex="-1">第一阶段：标准化框架（当前） <a class="header-anchor" href="#第一阶段-标准化框架-当前" aria-label="Permalink to &quot;第一阶段：标准化框架（当前）&quot;">​</a></h4><ul><li>提供标准化的任务框架和表单</li><li>确保数据规范和流程统一</li><li>建立完善的框架管理体系</li></ul><h4 id="第二阶段-ai增强-进行中" tabindex="-1">第二阶段：AI增强（进行中） <a class="header-anchor" href="#第二阶段-ai增强-进行中" aria-label="Permalink to &quot;第二阶段：AI增强（进行中）&quot;">​</a></h4><ul><li>在框架基础上增加AI智能推荐功能</li><li>AI辅助填充数据和生成内容</li><li>逐步引入自然语言理解能力</li></ul><h4 id="第三阶段-ai-skill-目标" tabindex="-1">第三阶段：AI Skill（目标） <a class="header-anchor" href="#第三阶段-ai-skill-目标" aria-label="Permalink to &quot;第三阶段：AI Skill（目标）&quot;">​</a></h4><ul><li>完全智能化的任务处理能力</li><li>支持自然语言交互和智能决策</li><li>实现真正的智能投后管理</li></ul><h3 id="当前已实现的ai能力" tabindex="-1">当前已实现的AI能力 <a class="header-anchor" href="#当前已实现的ai能力" aria-label="Permalink to &quot;当前已实现的AI能力&quot;">​</a></h3><p>虽然当前仍以框架为主要形式，但系统已逐步融入AI能力：</p><ol><li><strong>智能推荐</strong>：根据任务类型和企业特征推荐合适的框架</li><li><strong>自动填充</strong>：基于企业档案自动填充基础信息</li><li><strong>数据校验</strong>：AI辅助的数据质量检查和格式校验</li><li><strong>智能提示</strong>：根据上下文提供操作建议和帮助</li></ol><h3 id="未来ai-skill特性" tabindex="-1">未来AI Skill特性 <a class="header-anchor" href="#未来ai-skill特性" aria-label="Permalink to &quot;未来AI Skill特性&quot;">​</a></h3><p>随着演进的深入，AI Skill将具备以下核心能力：</p><ul><li><strong>动态理解</strong>：能够理解用户的自然语言描述，自动解析需求</li><li><strong>智能响应</strong>：根据用户输入智能生成个性化的任务内容</li><li><strong>主动服务</strong>：基于历史数据和上下文主动提供服务</li><li><strong>学习进化</strong>：通过持续学习不断优化处理逻辑</li><li><strong>场景适配</strong>：自动适应不同业务场景和用户需求</li></ul><h3 id="过渡期间的使用建议" tabindex="-1">过渡期间的使用建议 <a class="header-anchor" href="#过渡期间的使用建议" aria-label="Permalink to &quot;过渡期间的使用建议&quot;">​</a></h3><p>在从传统框架到AI Skill的过渡期间：</p><ol><li><strong>熟悉框架系统</strong>：掌握当前框架的使用方法，这是AI Skill的基础</li><li><strong>关注AI增强功能</strong>：留意系统新增的AI辅助功能</li><li><strong>反馈使用体验</strong>：您的反馈对AI能力的优化至关重要</li><li><strong>逐步适应新交互</strong>：尝试使用AI推荐等新功能，适应智能化操作方式</li></ol><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/using-system/task-management/create-task/">创建/编辑任务</a></li><li><a href="/using-system/task-management/attachments.html">添加附件</a></li><li><a href="/using-system/enterprise-archive/enterprise-file.html">企业档案管理</a></li><li><a href="/using-system/workbench/ai-assistant.html">AI资管助手</a></li></ul>',49)])])}const m=a(e,[["render",n]]);export{c as __pageData,m as default};
